/**
 * Sprout Design System — NavigationBar (Bottom Tab Bar)
 *
 * ✅ EXACT MATCH to Figma "Navigation Bar" (node: 100:8821)
 * Source page: ↪︎ Components · Figma file: EhpRiGZ5eJnBb132X9zewg
 *
 * Variants confirmed from live Figma scan (5 total):
 *   Type: Home (Events) | Memories | AI Assist | Chat | Clubs
 *
 * Key values extracted directly from Figma (not estimates):
 *   - Background: #F4F1EA (cream = Secondary/500) — VariableID:26:516
 *   - Shape: cornerRadius 9999 — full pill/capsule (floating nav)
 *   - Border: #E6E7EA 1px inside stroke (grey/100)
 *   - Height: 69px · Padding: l=16 r=16 t=12 b=12
 *   - Inner container: HORIZONTAL SPACE_BETWEEN (5 tab items)
 *   - Shadow 1: rgba(14,14,16,0.15) offset(4,5) blur=25 spread=3
 *   - Shadow 2: rgba(14,14,16,0.05) offset(2,5) blur=10 spread=0
 *
 *   Per tab item (Button container):
 *   - VERTICAL layout, CENTER align, gap=4
 *   - Width: ~52px, Height: 45px
 *   - Icon: 24×24
 *   - Label: Inter Regular 11px
 *
 *   Active state (pure color change — NO pill indicator):
 *   - Icon: filled/solid #186338 (brand/500)
 *   - Label: #186338 (brand/500)
 *
 *   Inactive state:
 *   - Icon: outlined/stroked #7D715E (warm brown)
 *   - Label: #7D715E
 *
 *   Chat badge (notification bubble):
 *   - Size: 16×16, cornerRadius: 100 (full circle)
 *   - Background: #186338 (brand/500)
 *   - Padding: l=5 r=5 t=2 b=2
 *   - Text: Inter Medium 10px, color #ffffff
 *
 * NOTE: This is a FLOATING PILL nav bar, positioned at the bottom of the screen
 * with horizontal margins. Use `position: 'absolute', bottom: X` with safe area inset.
 */

import React from 'react';
import {
  StyleSheet,
  Text,
  TouchableOpacity,
  View,
  ViewStyle,
} from 'react-native';

// ─── Raw Figma-extracted values ───────────────────────────────────────────────

const FIGMA = {
  // Container
  background:     '#F4F1EA',  // VariableID:26:516 — Secondary/500 (cream)
  borderColor:    '#E6E7EA',  // grey/100
  borderWidth:    1,
  cornerRadius:   9999,       // full pill shape — confirmed from scan

  // Dimensions
  barHeight:      69,
  paddingH:       16,         // left=16, right=16
  paddingV:       12,         // top=12, bottom=12

  // Tab item dimensions
  iconSize:       24,         // icon container 24×24
  tabGap:         4,          // gap between icon and label (itemSpacing=4)

  // Label font — Inter Regular 11px for BOTH active and inactive
  labelFont:          'Inter',
  labelFontWeight:    '400' as const,
  labelSize:          11,

  // Active state — icon fills + label become brand green
  activeColor:        '#186338',  // brand/500

  // Inactive state — icon strokes + label become warm brown
  inactiveColor:      '#7D715E',  // warm brown

  // Shadow layer 1 — larger, darker (confirmed from Figma effects array)
  shadow1Color:   '#0e0e10',
  shadow1Opacity: 0.15,
  shadow1OffsetX: 4,
  shadow1OffsetY: 5,
  shadow1Blur:    25,
  shadow1Spread:  3,

  // Shadow layer 2 — smaller, subtler
  shadow2Color:   '#0e0e10',
  shadow2Opacity: 0.05,
  shadow2OffsetX: 2,
  shadow2OffsetY: 5,
  shadow2Blur:    10,
  shadow2Spread:  0,

  // Chat badge (notification bubble)
  badgeBg:         '#186338',  // brand/500 — same as active
  badgeSize:       16,
  badgeRadius:     100,
  badgePaddingH:   5,
  badgePaddingV:   2,
  badgeFontSize:   10,
  badgeFontFamily: 'Inter',
  badgeFontWeight: '500' as const,
  badgeTextColor:  '#ffffff',
};

// ─── Types ───────────────────────────────────────────────────────────────────

/** Sprout tab keys — match Figma "Type" variant property */
export type NavTabKey = 'events' | 'memories' | 'ai-assist' | 'chat' | 'clubs' | string;

export interface NavTab {
  /** Unique key, used as the activeTab identifier */
  key: NavTabKey;
  /** Label shown below icon (Inter Regular 11px) */
  label: string;
  /**
   * Icon renderer — receives `active` boolean.
   * When active=true:  render FILLED/SOLID icon in color #186338
   * When active=false: render OUTLINED icon in color #7D715E
   */
  icon: (active: boolean) => React.ReactNode;
  /** Optional notification count shown as a badge (e.g. Chat tab) */
  badge?: number;
}

export interface NavigationBarProps {
  tabs: NavTab[];
  activeTab: NavTabKey;
  onTabPress: (key: NavTabKey) => void;
  /**
   * Safe-area bottom inset.
   * Use 34px on iPhone with home indicator, 0px on Android / older iPhone.
   * Pass `insets.bottom` from react-native-safe-area-context.
   */
  bottomInset?: number;
  /** Horizontal margin from screen edge (default 16px) */
  sideMargin?: number;
  /** Container style override */
  style?: ViewStyle;
}

// ─── Component ───────────────────────────────────────────────────────────────

export const NavigationBar: React.FC<NavigationBarProps> = ({
  tabs,
  activeTab,
  onTabPress,
  bottomInset = 34,
  sideMargin = 16,
  style,
}) => {
  return (
    <View
      style={[
        styles.outer,
        { paddingBottom: bottomInset, paddingHorizontal: sideMargin },
        style,
      ]}
    >
      {/* ── Pill container ─────────────────────────────────────────────────── */}
      <View style={styles.pill}>
        {tabs.map((tab) => {
          const isActive = tab.key === activeTab;

          return (
            <TouchableOpacity
              key={tab.key}
              style={styles.tabItem}
              onPress={() => onTabPress(tab.key)}
              activeOpacity={0.75}
              accessibilityRole="tab"
              accessibilityState={{ selected: isActive }}
              accessibilityLabel={tab.label}
            >
              {/* Icon area — with optional notification badge */}
              <View style={styles.iconArea}>
                <View style={styles.iconWrapper}>
                  {tab.icon(isActive)}
                </View>

                {/* Badge — shown when tab.badge > 0 */}
                {tab.badge != null && tab.badge > 0 && (
                  <View style={styles.badge}>
                    <Text style={styles.badgeText}>
                      {tab.badge > 99 ? '99+' : String(tab.badge)}
                    </Text>
                  </View>
                )}
              </View>

              {/* Label — Inter Regular 11px */}
              <Text
                style={[
                  styles.label,
                  { color: isActive ? FIGMA.activeColor : FIGMA.inactiveColor },
                ]}
                numberOfLines={1}
              >
                {tab.label}
              </Text>
            </TouchableOpacity>
          );
        })}
      </View>
    </View>
  );
};

// ─── Styles ──────────────────────────────────────────────────────────────────

const styles = StyleSheet.create({
  // Outer wrapper — handles safe area spacing and side margins
  outer: {
    width: '100%',
  },

  // The floating pill container — exact Figma shape
  pill: {
    flexDirection:    'row',
    alignItems:       'center',
    justifyContent:   'space-between',

    height:           FIGMA.barHeight,
    borderRadius:     FIGMA.cornerRadius,
    backgroundColor:  FIGMA.background,

    // Border from Figma (INSIDE stroke → use borderWidth)
    borderWidth:      FIGMA.borderWidth,
    borderColor:      FIGMA.borderColor,

    // Horizontal padding from Figma (l=16, r=16)
    paddingHorizontal: FIGMA.paddingH,

    // iOS dual-layer shadow (using dominant layer 1 values)
    shadowColor:      FIGMA.shadow1Color,
    shadowOffset:     { width: FIGMA.shadow1OffsetX, height: FIGMA.shadow1OffsetY },
    shadowRadius:     FIGMA.shadow1Blur / 2,
    shadowOpacity:    FIGMA.shadow1Opacity,

    // Android elevation (approximates shadow depth)
    elevation:        12,

    overflow:         'hidden',
  },

  // Individual tab button
  tabItem: {
    flex:           1,
    alignItems:     'center',
    justifyContent: 'center',
    gap:            FIGMA.tabGap,      // 4px between icon and label
    paddingVertical: FIGMA.paddingV,   // 12px top + bottom
  },

  // Icon area wrapper (supports badge positioning)
  iconArea: {
    position:  'relative',
    width:     FIGMA.iconSize,
    height:    FIGMA.iconSize,
  },

  // Icon inner wrapper — centers the icon
  iconWrapper: {
    width:           FIGMA.iconSize,
    height:          FIGMA.iconSize,
    alignItems:      'center',
    justifyContent:  'center',
  },

  // Notification badge — positioned top-right of icon
  badge: {
    position:         'absolute',
    top:              -4,
    right:            -6,
    minWidth:         FIGMA.badgeSize,
    height:           FIGMA.badgeSize,
    borderRadius:     FIGMA.badgeRadius,
    backgroundColor:  FIGMA.badgeBg,
    paddingHorizontal: FIGMA.badgePaddingH,
    paddingVertical:  FIGMA.badgePaddingV,
    alignItems:       'center',
    justifyContent:   'center',
  },

  badgeText: {
    fontSize:        FIGMA.badgeFontSize,
    fontFamily:      FIGMA.badgeFontFamily,
    fontWeight:      FIGMA.badgeFontWeight,
    color:           FIGMA.badgeTextColor,
    lineHeight:      FIGMA.badgeFontSize * 1.2,
  },

  // Tab label
  label: {
    fontSize:      FIGMA.labelSize,
    fontFamily:    FIGMA.labelFont,
    fontWeight:    FIGMA.labelFontWeight,
    lineHeight:    FIGMA.labelSize * 1.5,
  },
});

export default NavigationBar;
